INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_1506_L071$$, 2026, $$This line item funds Fleet Electronic Warfare Support Group (FEWSG) installations. These installations are modifications to fleet systems based on the Adversary and FEWSG Electronic Attack Digital Radio
 Frequency Memory (DRFM) Roadmap. The program focuses on the FEWSG DRFM modification schedule and support of the required engineering and logistics to accomplish these upgrades. These systems
 provide Adversarial peer and near peer Electronic Warfare (EW) effects on USN sensor systems. USN operators must overcome these effects to demonstrate spectrum dominance and electromagnetic
 maneuver warfare (EMW) in an EW contested environment. Operational Safety Improvement Program (OSIP) 119-83 title includes new nomenclature ALQ-255/256 as a result of DRFM Engineering Change
 Proposal (ECP).$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Navy                                                                                                                     Date: April 2026
