INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_1506_L073$$, 2026, $$This line item funds modifications to the E-6B Mercury aircraft to improve mission capability and readiness. All sixteen (16) aircraft, unless otherwise noted, in the E-6B fleet will receive each modification. The
 E-6B is a manned airborne communications platform designed to provide a survivable, endurable, and reliable airborne Command, and Control, and Communications capability in support of the President,
 Secretary of War, and United States strategic and non-strategic forces.

 - Safety Deficiencies (OSIP 008-02) corrects high risk aircraft safety hazards to protect personnel and equipment enabling mission readiness.

 - Tech Insertion (OSIP 003-04) corrects aircraft obsolescence, supportability, weight management and interoperability deficiencies through new technology insertion enabling mission readiness and mandate
 compliance.

 - Service Life Extension Program (OSIP 003-07) extends the service life of the aircraft to 2038+ through airframe strengthening and structural data recording and analysis.

 - Communications Upgrade (OSIP 012-07) installs expanded aircraft digital communication paths and processing to improve airborne command post operations and modernizes direct over-the-horizon
 communications links to deployed strategic forces.

 - Multi-Role Tactical Common Data Link (OSIP 013-10) installs expanded aircraft communication bandwidth capability required to interoperate with United States Strategic Command's National Command and
 Control Architecture.

 - Auxiliary Power Unit (APU) (OSIP 002-12) corrects airborne command post operational test deficiencies by installing an improved APU to meet increased aircraft power requirements.

 - Family of Advanced Beyond-Line-of-Sight Terminals/Presidential and National Voice Conferencing (FAB-T/PNVC) (OSIP 014-14) replaces obsolete Military Strategic Tactical Relay terminals with improved
 FAB-T and replaces Secure Emergency Conferencing Network with PNVC.

 - Mission Systems (OSIP 014-21) addresses obsolescence and supportability upgrades through technology insertion of commercial and government off the shelf (COTs/GOTs) systems.$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Navy                                                                                                                    Date: April 2026
