INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_1507_L013$$, 2026, $$The Joint Air-to-Ground Missile (JAGM) is an Army-led air-launched missile system that incorporates multi-mode seeker technology thus providing advanced Line-of-Sight and Beyond-Line-of-Sight precision fire-
 and-forget seeker targeting capabilities resulting in increased lethality against soft, hardened, moving, stationary, land, and maritime threats. JAGM improves the warfighter's capability in adverse weather, day
 or night, and in obscured/countermeasure environments. The JAGM Increment 1 system will replace aviation-launched, Tube-launched, Optically-tracked, Wire-guided (TOW) missile, and Helicopter-Launched
 Fire-&-Forget (HELLFIRE) Missile Systems. JAGM addresses rotary wing and unmanned aerial vehicle requirements. The Department of The Navy threshold platform is AH-1Z. The JAGM system includes the
 missile, trainers, containers, support equipment, M299 Launcher, and system software modification. Missile configurations include the JAGM Tactical Missile, Captive Air Training Missile (CATM) and Air Training
 Missile. JAGM procurement funding supports the entire JAGM system to include resolution of obsolescence, safety, reliability, weapon integration activities, test sets, engineering services, production ramp-up
 activities, and production issues.

 Prior Year Total Quantity is 1,413; 1,361 JAGM and 52 CATM$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Navy                                                                                                                     Date: April 2026
