INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_1507_L021$$, 2026, $$The Precision Attack Strike Munition is an air-launched missile that provides a longer-range, precision strike weapon capable of deterring and engaging maritime and land-based targets. PASM builds off of the
 subsystem maturation, integration, and demonstration efforts of the Long-Range Attack Munition (LRAM) Joint Capability Technology Demonstration (JCTD). PASM will provide asymmetric advantages in range,
 stand-off and lethality. PASM is designed with a Weapons Open System Architecture (WOSA) to form fit multiple types of payloads based on mission while using common mounting systems and launchers to
 simplify logistics requirements. PASM is initially designed to utilize mature, non-integrated capabilities for the fire control system. The AH-1Z is the threshold platform for the USMC. The PASM system includes
 missiles, trainers, containers, federated platform integration solution, support equipment, modular payloads, and software modifications.$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Navy                                                                                                                      Date: April 2026
