INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_1508_L011$$, 2026, $$Program provides for Other Ship Gun Ammunition which consists of medium caliber types (20MM, 25MM, 30MM, 40MM). This supports Navy ships, and active and reserve ashore warfare forces including Naval
 Expeditionary Combat Command (NECC), Mobile Security Forces (MSF), fleet combat readiness groups, inshore undersea warfare groups and several other types of operational units. Program includes support
 for emergent anti-terrorism/force protection and homeland defense requirements.

 Program provides for Other Ship Gun Ammunition support for Naval Special Warfare (NSW) service common munitions which are required to provide US Navy SEAL teams, NSW small tactical units and task
 groups, and Special Boat Teams with a fire power advantage, area target engagement, standoff and extended range capability, as well as an anti-armor capability. This includes medium caliber mortars (20MM -
 81MM) and Javelin. These munitions provide NSW an essential force protection capability and increases the combat power of NSW tactical elements.$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Navy                                                                                                                     Date: April 2026
