INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_1508_L009$$, 2027, $$Program procures conventional 5"/54 ammunition and Counter Unmanned Aerial Systems (C-UAS) Hypervelocity Projectile (HVP) rounds supporting CENTCOM Operations Transfer, Israel Security
 Supplemental (P.L. 118-50, Division A., Sec. 101). Both ammunition are fired from MK 45 gun installed on Cruiser and Destroyer combatant ships against air, surface, and shore targets. Conventional 5"/54
 Ammunition items procured includes propelling charges, high-explosive projectiles, fuzes, and training rounds.

