INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_1508_L015$$, 2026, $$This program provides funding for ammunition with a value less than $5 million. These pyrotechnic devices consist of Parachute Flares (Paraflares) and Marine Location Markers (MLMs). Paraflares provide
 battlefield illumination of surface areas in search and attack operations in the near infrared spectrum and are deployed from fixed wing aircraft (racks or dispensers) or rotary wing aircraft (dispensers). MLMs
 produce both a yellow flame and white smoke and are visible for three miles under normal operating conditions. MLMs are deployed from fixed-wing aircraft racks or hand-deployed from rotary-wing aircraft.
 MLMs are also hand deployed from surface vessels.

 The Mk-25 and Mk-58 MLM units are used in a variety of situations to include Search and Rescue operations, Man Overboard drills, and Target Marking in support of Fleet Operations and Readiness.$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Navy                                                                                                                     Date: April 2026
