INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_1508_L016$$, 2027, $$The Expeditionary Loitering Munitions Portfolio consists of a family of Navy loitering munition programs (air and surface) designed to meet an urgent Geographic Combatant Command Requirement. Air and
 Surface Expeditionary Loitering Munitions will leverage and continue prior development efforts including an Office of Naval Research (ONR) Innovative Naval Prototype (INP). The Navy is pursuing commercial-
 off-the-shelf solutions with autonomous government-provided software and auxiliary systems. The systems will be expeditionary and deployable by small teams to support operations in various environments. The
 air system has transitioned from Low-Rate Initial Production to Full-Rate Production with the initial vendor solutions and is now expanding the industrial base for this capability by integrating government-owned
 technology with other vendor platform solutions. The surface system has transitioned from the ONR INP and is now in Low-Rate Initial Production.

 FY 2026 spend plan for air system production includes $0 thousand of discretionary funding and $247,000 thousand of mandatory funding for a total of $247,000 thousand. Mandatory funds support the contract
 award for Phase III production of 660 rounds.

 [P40A / C-UAS Theodore Roosevelt Carrier Strike Group Munitions]: This newly established cost element funded an emergent requirement in support of the Counter-Unmanned Aircraft Systems (C-UAS)
 Theodore Roosevelt Carrier Strike Group (TRSCG) Munitions, funding C-UAS All Up Rounds (AUR) Prototyping Kinetic Build Munitions in FY 2025.

 [P40A / AIR SYSTEM MATERIALS]: Air system materials funding procures long lead time material to facilitate rapid procurement efforts.

 [P40A / AIR SYSTEM PRODUCTION]: Air system production funding supports NRE associated with munition production as well as management reserve for cost type contract expenses.

 [P40A / AIR SYSTEM MUNITIONS]: Air system munition funding supports production of All Up Round air systems and Ground Support Equipment.$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Navy                                                                                                                     Date: April 2026
