INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_1508_L023$$, 2026, $$The Items Less Than $5 Million budget is crucial for ensuring the operational readiness and lethality of the Marine Corps by funding distinct, mission-essential ammunition requirements.

 This funding provides for the First Destination Transportation Charge (FDTC), guaranteeing the timely and reliable delivery of ammunition from production facilities directly to our warfighters. Without it, the
 ammunition supply chain is broken.

 Funding also provides the mission-critical ammunition for the Marine Security Guard Battalion, ensuring Marines can execute their no-fail mission of protecting U.S. embassies and diplomatic personnel
 worldwide.

 In addition, this line item enhances the core marksmanship of the force by equipping the Marine Corps Competition Shooting Team with unique precision ammunition, which serves to test, validate, and pioneer
 advanced shooting techniques that are disseminated across the Corps.$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Navy                                                                                                                     Date: April 2026
