INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_1508_L024$$, 2026, $$The 1085 Mortar Ammunition budget procures and provides the Fleet Marine Force with 60MM mortar ammunition and 81MM mortar ammunition in provision of training and war reserve munitions requirements
 for Lightweight and Medium Weight Mortar Systems. The family of Mortar Cartridges includes all 60MM mortar cartridges and 81MM mortar cartridges which consist of high explosive, smoke, illumination and full
 range training practice rounds

 The 60mm Mortar cartridges are designed for use with the M224 60mm Lightweight Company Mortar System (LWCMS), a key indirect fire support weapon for Marine Corps infantry units. The M224's short
 minimum range makes its ammunition highly effective for:
 -Close protective fires against assaulting enemy forces.
 -Urban combat, including block-to-block fighting.
 -Engagements in close terrain with restricted visibility.

 The 81mm Mortar cartridges are designed for use with the M252 Mortar Weapon System, a crucial asset for providing medium-range indirect fire in support of Marine Corps infantry battalions.
 The M252 system enables battalion commanders to:
 -Engage targets at greater distances, beyond the reach of company-level assets.
 -Suppress, neutralize, and destroy enemy personnel and positions.
 -Provide battlefield obscuration and illumination to support maneuver.$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Navy                                                                                                                    Date: April 2026
