INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_1611_L039$$, 2026, $$Auxiliary Personnel Lighter (Small) - APL(S) barracks craft provide berthing and messing facilities for sailors while their ships are in port for availabilities and inter-deployment training cycles. It supports up to
 an aircraft carrier (CVN) size ship where it is designed to provide berthing for up to 600 personnel and messing for up to 1,130 personnel. APL(S) facilities include classrooms, conference rooms, administrative
 offices, disbursing office, galley, mess, scullery, post office, convenience store, barbershop, lounges, laundry facilities, physical fitness center, chaplain's office, medical complex, quarterdeck, equipment/
 machinery rooms, and various storerooms. Lastly, it provides berthing and sanitary facilities designed for dual-gender use.

 Characteristics:                         APL
 Length Overall                           269 ft
 Beam                                     69 ft
 Displacement                             3315 MT
 Draft                                    8 ft

 Production Status:                                      APL 73                    APL 2501                APL 2601                  APL 2701
 Contract Award Date                                     Sep 2024                  Jun 2026                Nov 2026                  Jun 2027
